            byte[] content = IOUtils.toByteArray(inputStream);

            // Double-check actual size read
            if (content.length > MAX_CONTENT_LENGTH_BYTES) {
                throw new SecurityException("Downloaded content exceeds maximum allowed size");
            }

            return content;

        } finally {
            IOUtils.closeQuietly(inputStream);
            if (connection != null) {
                connection.disconnect();
            }
        }
    }

    /**
     * Creates a URL with validation to prevent common attacks.
     */
    private URL createSafeUrl(String resourceUrl) throws MalformedURLException {
        // Basic protocol whitelist - only allow http and https
        String lowerUrl = resourceUrl.toLowerCase().trim();
        if (!lowerUrl.startsWith("http://") && !lowerUrl.startsWith("https://")) {
            throw new IllegalArgumentException("Only HTTP and HTTPS protocols are supported");
        }

        // Prevent CRLF injection
        if (resourceUrl.contains("\r") || resourceUrl.contains("\n")) {
            throw new IllegalArgumentException("Invalid characters in URL");
        }

        return new URL(resourceUrl);
    }

    /**
     * Opens a connection with redirect handling and security checks.
     */
    private HttpURLConnection openConnectionWithRedirects(URL url, int redirectCount) throws IOException {
        if (redirectCount > MAX_REDIRECTS) {
            throw new SecurityException("Too many redirects detected, possible redirect loop");
        }

        HttpURLConnection connection = (HttpURLConnection) url.openConnection();
        connection.setConnectTimeout(CONNECT_TIMEOUT_MS);
        connection.setReadTimeout(READ_TIMEOUT_MS);
        connection.setInstanceFollowRedirects(false); // Handle redirects manually for security

        // Set reasonable request properties
        connection.setRequestProperty("User-Agent", "CMS-RemoteResourceService/1.0");
        connection.setRequestProperty("Accept", "*/*");

        int responseCode = connection.getResponseCode();

        // Handle redirects manually to validate target URLs
        if (responseCode == HttpURLConnection.HTTP_MOVED_PERM ||
            responseCode == HttpURLConnection.HTTP_MOVED_TEMP ||
            responseCode == HttpURLConnection.HTTP_SEE_OTHER ||
            responseCode == 307 || // Temporary Redirect
            responseCode == 308) { // Permanent Redirect

            String location = connection.getHeaderField("Location");
            connection.disconnect();

            if (location == null || location.isEmpty()) {
                throw new IOException("Redirect location header is missing");
            }

            // Resolve relative URLs
            URL redirectUrl = new URL(url, location);

            // Validate redirect protocol - don't downgrade from HTTPS to HTTP
            if (url.getProtocol().equalsIgnoreCase("https") && 
                !redirectUrl.getProtocol().equalsIgnoreCase("https")) {
                throw new SecurityException("Downgrade from HTTPS to HTTP is not allowed");
            }

            // Validate redirect URL
            createSafeUrl(redirectUrl.toString());

            return openConnectionWithRedirects(redirectUrl, redirectCount + 1);
        }

        if (responseCode != HttpURLConnection.HTTP_OK) {
            connection.disconnect();
            throw new IOException("Server returned HTTP response code: " + responseCode);
        }

        return connection;
    }
}
